package residentevm
import ("bytes";"testing"; oldproto "github.com/golang/protobuf/proto")
func TestTypedOneofVariantsHaveDistinctWireTags(t *testing.T){ rs:=[]isTypedRecordV1_Record{&TypedRecordV1_Hello{Hello:&Hello{}},&TypedRecordV1_PostStartBlock{PostStartBlock:&PostStartBlockWithSenders{}},&TypedRecordV1_IncludedTransaction{IncludedTransaction:&IncludedTransaction{}},&TypedRecordV1_IncludedGroup{IncludedGroup:&IncludedGroup{}},&TypedRecordV1_MessageCommitted{MessageCommitted:&MessageCommitted{}},&TypedRecordV1_BuildAborted{BuildAborted:&BuildAborted{}},&TypedRecordV1_Gap{Gap:&Gap{}},&TypedRecordV1_Reorg{Reorg:&Reorg{}},&TypedRecordV1_EpochReset{EpochReset:&EpochReset{}}}; seen:=map[string]bool{}; for _,r:=range rs { b,e:=MarshalTypedRecord(&TypedRecordV1{WireVersion:1,SchemaVersion:1,SchemaHash:TypedSchemaHash(),Record:r});if e!=nil{t.Fatal(e)};if len(b)==0{t.Fatal("empty")}; key:=string(b);if seen[key]{t.Fatal("duplicate oneof wire")};seen[key]=true;var out TypedRecordV1;if e:=UnmarshalTypedRecord(b,&out);e!=nil{t.Fatal(e)} } }
func TestTypedSchemaHashAndDeterministicBytes(t *testing.T){m:=&TypedRecordV1{WireVersion:1,SchemaVersion:1,SchemaHash:TypedSchemaHash(),Record:&TypedRecordV1_MessageCommitted{MessageCommitted:&MessageCommitted{MessageHash:bytes.Repeat([]byte{7},32)}}};a,e:=MarshalTypedRecord(m);if e!=nil{t.Fatal(e)};b,e:=MarshalTypedRecord(m);if e!=nil||!bytes.Equal(a,b){t.Fatal("nondeterministic")} ;if !bytes.Equal(TypedSchemaHash(),TypedSchemaHash()){t.Fatal("unstable hash")} }
func TestTypedRecordRejectsUnknownSchema(t *testing.T){m:=&TypedRecordV1{Record:&TypedRecordV1_Gap{Gap:&Gap{}}};if _,e:=MarshalTypedRecord(m);e!=nil{t.Fatal(e)};raw,_:=oldproto.Marshal(m);var out TypedRecordV1;if e:=UnmarshalTypedRecord(raw,&out);e!=nil{t.Fatal(e)};m.SchemaHash=[]byte("bad");if _,e:=MarshalTypedRecord(m);e==nil{t.Fatal("accepted bad schema")} }
